def findRotation(self, mat, target):
    n = len(mat)
    for _ in range(4):
        if mat == target:
            return True
        mat = [list(row) for row in zip(*mat[::-1])]
    return False

class Solution {
public:
    bool findRotation(vector<vector<int>>& mat, vector<vector<int>>& target) {
        int n = mat.size();
        for (int r = 0; r < 4; r++) {
            if (mat == target) return true;
            vector<vector<int>> rot(n, vector<int>(n));
            for (int i = 0; i < n; i++)
                for (int j = 0; j < n; j++)
                    rot[j][n-1-i] = mat[i][j];
            mat = rot;
        }
        return false;
    }
};

class Solution {
    public boolean findRotation(int[][] mat, int[][] target) {
        int n = mat.length;
        for (int r = 0; r < 4; r++) {
            if (Arrays.deepEquals(mat, target)) return true;
            int[][] rot = new int[n][n];
            for (int i = 0; i < n; i++)
                for (int j = 0; j < n; j++)
                    rot[j][n-1-i] = mat[i][j];
            mat = rot;
        }
        return false;
    }
}

def mirrorReflection(self, p, q):
    from math import gcd
    g = gcd(p, q)
    k = q // g
    m = p // g
    if k % 2 == 0:
        return 2
    if m % 2 == 0:
        return 0
    return 1

class Solution {
public:
    int mirrorReflection(int p, int q) {
        int g = gcd(p, q);
        int k = q / g, m = p / g;
        if (k % 2 == 0) return 2;
        if (m % 2 == 0) return 0;
        return 1;
    }
};

class Solution {
    public int mirrorReflection(int p, int q) {
        int g = gcd(p, q);
        int k = q / g, m = p / g;
        if (k % 2 == 0) return 2;
        if (m % 2 == 0) return 0;
        return 1;
    }
    int gcd(int a, int b) {
        return b == 0 ? a : gcd(b, a % b);
    }
}

#include <bits/stdc++.h>
using namespace std;

int main() {
    int n; cin >> n;
    vector<double> ang(n);
    for (int i = 0; i < n; i++) {
        double x, y; cin >> x >> y;
        ang[i] = atan2(y, x) * 180 / M_PI;
    }
    sort(ang.begin(), ang.end());
    double max_gap = 0;
    for (int i = 0; i < n; i++) {
        double gap = ang[(i+1)%n] - ang[i];
        if (i == n-1) gap += 360;
        max_gap = max(max_gap, gap);
    }
    cout << fixed << setprecision(10) << 360 - max_gap << "\n";
}

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        double[] ang = new double[n];
        for (int i = 0; i < n; i++) {
            double x = sc.nextDouble(), y = sc.nextDouble();
            ang[i] = Math.toDegrees(Math.atan2(y, x));
        }
        Arrays.sort(ang);
        double maxGap = 0;
        for (int i = 0; i < n; i++) {
            double gap = ang[(i+1)%n] - ang[i];
            if (i == n-1) gap += 360;
            maxGap = Math.max(maxGap, gap);
        }
        System.out.printf("%.10f%n", 360 - maxGap);
    }
}
